/** Grava a base inicial na conta de quem está logado. Chama onProgresso(texto). */
export async function importarBase(onProgresso = () => {}) {
  onProgresso('Gravando as contas fixas…');
  await fixosApi.inserirVarias(BASE.fixos);

  onProgresso(`Gravando ${BASE.tx.length} contas…`);
  await contasApi.inserirVarias(BASE.tx);

  const v0 = BASE.viagens[0];
  onProgresso('Criando a viagem…');
  const v = await viagemApi.criar(v0);
  onProgresso(`Gravando ${v0.hosp.length} estadias…`);
  await viagemApi.addHospVarias(v.id, v0.hosp);
  onProgresso(`Gravando ${v0.gastos.length} gastos da viagem…`);
  await viagemApi.addGastosVarios(v.id, v0.gastos);

  return { contas: BASE.tx.length, fixos: BASE.fixos.length,
           hosp: v0.hosp.length, gastos: v0.gastos.length };
}

/** true se a conta já tem alguma coisa (para não importar duas vezes). */
export const temBase = () => S.tx.length > 0 || S.viagens.length > 0;
